import express, { type Express } from "express";
import fs from "fs";
import path from "path";
import { createServer as createViteServer, createLogger } from "vite";
import { type Server } from "http";
import viteConfig from "../vite.config";
import { nanoid } from "nanoid";

const viteLogger = createLogger();

export function log(message: string, source = "express") {
  const formattedTime = new Date().toLocaleTimeString("en-US", {
    hour: "numeric",
    minute: "2-digit",
    second: "2-digit",
    hour12: true,
  });

  console.log(`${formattedTime} [${source}] ${message}`);
}

export async function setupVite(app: Express, server: Server) {
  const serverOptions = {
    middlewareMode: true,
    hmr: { server },
    allowedHosts: true as const,
  };

  const vite = await createViteServer({
    ...viteConfig,
    configFile: false,
    customLogger: {
      ...viteLogger,
      error: (msg, options) => {
        viteLogger.error(msg, options);
        process.exit(1);
      },
    },
    server: serverOptions,
    appType: "custom",
  });

  app.use(vite.middlewares);
  app.use("*", async (req, res, next) => {
    const url = req.originalUrl;

    try {
      const clientTemplate = path.resolve(
        import.meta.dirname,
        "..",
        "client",
        "index.html",
      );

      // always reload the index.html file from disk incase it changes
      let template = await fs.promises.readFile(clientTemplate, "utf-8");
      template = template.replace(
        `src="/src/main.tsx"`,
        `src="/src/main.tsx?v=${nanoid()}"`,
      );
      const page = await vite.transformIndexHtml(url, template);
      res.status(200).set({ "Content-Type": "text/html" }).end(page);
    } catch (e) {
      vite.ssrFixStacktrace(e as Error);
      next(e);
    }
  });
}

export function serveStatic(app: Express) {
  const distPath = path.resolve(import.meta.dirname, "public");

  if (!fs.existsSync(distPath)) {
    throw new Error(
      `Could not find the build directory: ${distPath}, make sure to build the client first`,
    );
  }

  app.use(express.static(distPath));

  // fall through to index.html if the file doesn't exist
  app.use("*", (_req, res) => {
    res.sendFile(path.resolve(distPath, "index.html"));
  });
}

client/src/components/MoodCheckPopup.tsx.content:
import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import { X } from "lucide-react";
import type { EmotionType, MoodEntry } from "@shared/schema";

const EMOTION_EMOJIS: Record<EmotionType, string> = {
  happiness: "😊",
  sadness: "😢",
  anger: "😠",
  calm: "😌",
  excitement: "🤩",
};

const EMOTION_PROMPTS: Record<EmotionType, string> = {
  happiness: "What made you happy today?",
  sadness: "What's making you feel sad?",
  anger: "What's bothering you?",
  calm: "What's bringing you peace?",
  excitement: "What's got you excited?",
};

interface GlobalEmotionData {
  emotion: EmotionType;
  count: number;
  percentage: number;
}

interface MoodCheckPopupProps {
  open: boolean;
  onClose: () => void;
  onSaveMood: (emotion: EmotionType, reason: string, shouldPost: boolean) => Promise<void>;
  globalEmotions?: GlobalEmotionData[];
  existingMood?: MoodEntry | null;
}

export default function MoodCheckPopup({ 
  open, 
  onClose, 
  onSaveMood,
  globalEmotions = [],
  existingMood
}: MoodCheckPopupProps) {
  const [step, setStep] = useState<"select" | "entry">("select");
  const [selectedEmotion, setSelectedEmotion] = useState<EmotionType | null>(null);
  const [reason, setReason] = useState("");
  const [saving, setSaving] = useState(false);

  const handleEmotionSelect = (emotion: EmotionType) => {
    setSelectedEmotion(emotion);
    setStep("entry");
  };

  const handleClose = () => {
    onClose();
    resetState();
  };

  const handleSave = async (shouldPost: boolean) => {
    if (!selectedEmotion) return;

    // Check if user has written a reason
    if (!reason.trim()) {
      return; // Don't save if no reason provided
    }

    setSaving(true);
    try {
      await onSaveMood(selectedEmotion, reason.trim(), shouldPost);
      onClose();
      resetState();
    } catch (error) {
      console.error("Failed to save mood:", error);
    } finally {
      setSaving(false);
    }
  };

  const resetState = () => {
    setStep("select");
    setSelectedEmotion(null);
    setReason("");
  };

  return (
    <Dialog open={open} onOpenChange={(isOpen) => !isOpen && handleClose()}>
      <DialogContent className="sm:max-w-xl" data-testid="dialog-mood-check">
        <div className="absolute right-4 top-4">
          <Button
            variant="ghost"
            size="icon"
            onClick={handleClose}
            className="h-8 w-8"
            data-testid="button-close-mood"
          >
            <X className="h-4 w-4" />
          </Button>
        </div>

        <AnimatePresence mode="wait">
          {step === "select" && (
            <motion.div
              key="select"
              initial={{ opacity: 0, scale: 0.95 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0, scale: 0.95 }}
              className="space-y-6 py-6"
            >
              <h3 className="text-2xl font-display font-semibold text-center">How are you feeling?</h3>
              <p className="text-center text-muted-foreground text-sm">
                Select an emoji that represents your current mood
              </p>
              <div className="grid grid-cols-5 gap-4">
                {Object.entries(EMOTION_EMOJIS).map(([emotion, emoji]) => (
                  <motion.button
                    key={emotion}
                    onClick={() => handleEmotionSelect(emotion as EmotionType)}
                    className="flex flex-col items-center gap-2 p-4 rounded-2xl hover-elevate active-elevate-2 transition-all"
                    whileHover={{ scale: 1.05 }}
                    whileTap={{ scale: 0.95 }}
                    data-testid={`button-emotion-${emotion}`}
                  >
                    <span className="text-5xl">{emoji}</span>
                    <span className="text-xs capitalize text-muted-foreground">
                      {emotion}
                    </span>
                  </motion.button>
                ))}
              </div>
            </motion.div>
          )}

          {step === "entry" && selectedEmotion && (
            <motion.div
              key="entry"
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -20 }}
              className="space-y-6 py-6"
            >
              <div className="text-center space-y-2">
                <span className="text-6xl">{EMOTION_EMOJIS[selectedEmotion]}</span>
                <h3 className="font-semibold text-lg">
                  {EMOTION_PROMPTS[selectedEmotion]}
                </h3>
              </div>

              <div className="space-y-2">
                <Textarea
                  value={reason}
                  onChange={(e) => setReason(e.target.value)}
                  placeholder="Write about how you're feeling..."
                  className="min-h-32 resize-none"
                  maxLength={500}
                  data-testid="input-mood-reason"
                />
                <p className="text-xs text-muted-foreground text-right">
                  {reason.length}/500
                </p>
              </div>

              {/* Show buttons only after user types something */}
              {reason.trim().length > 0 && (
                <motion.div
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  className="space-y-3"
                >
                  <p className="text-sm text-center text-muted-foreground">What would you like to do?</p>
                  <div className="flex gap-3">
                    <Button
                      variant="outline"
                      onClick={() => handleSave(false)}
                      disabled={saving}
                      className="flex-1 h-14 text-base"
                      data-testid="button-add-to-diary"
                    >
                      Add to Diary
                    </Button>
                    <Button
                      onClick={() => handleSave(true)}
                      disabled={saving}
                      className="flex-1 h-14 text-base bg-gradient-to-r from-emotion-happiness to-emotion-excitement"
                      data-testid="button-post"
                    >
                      Post
                    </Button>
                  </div>
                  <p className="text-xs text-center text-muted-foreground">
                    Diary is private • Post is public
                  </p>
                </motion.div>
              )}
            </motion.div>
          )}
        </AnimatePresence>
      </DialogContent>
    </Dialog>
  );
}

client/src/components/SettingsPanel.tsx.content:
import { useState, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { X, LogOut, Lock, Globe, MessageCircle, Users } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";
import { Separator } from "@/components/ui/separator";
import { Card } from "@/components/ui/card";
import { useAuth } from "@/lib/auth-context";
import { useToast } from "@/hooks/use-toast";
import { doc, setDoc } from "firebase/firestore";
import { db } from "@/lib/firebase";

interface SettingsPanelProps {
  open: boolean;
  onClose: () => void;
}

export default function SettingsPanel({ open, onClose }: SettingsPanelProps) {
  const { currentUser, userData, signOut, refreshUserData } = useAuth();
  const { toast } = useToast();
  const [darkMode, setDarkMode] = useState(false);
  const [diaryPublic, setDiaryPublic] = useState(true);
  const [allowAnonymousMessages, setAllowAnonymousMessages] = useState(true);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    // Load dark mode from localStorage
    const isDark = localStorage.getItem("theme") === "dark";
    setDarkMode(isDark);

    // Load user settings
    if (userData?.settings) {
      setDiaryPublic(userData.settings.diaryPublic ?? true);
      setAllowAnonymousMessages(userData.settings.allowAnonymousMessages ?? true);
    }
  }, [userData]);

  const toggleDarkMode = async (checked: boolean) => {
    setDarkMode(checked);
    if (checked) {
      document.documentElement.classList.add("dark");
      localStorage.setItem("theme", "dark");
    } else {
      document.documentElement.classList.remove("dark");
      localStorage.setItem("theme", "light");
    }
  };

  const handleSettingChange = async (setting: string, value: boolean) => {
    if (!currentUser) return;

    try {
      setSaving(true);

      if (setting === "diaryPublic") {
        setDiaryPublic(value);
      } else if (setting === "allowAnonymousMessages") {
        setAllowAnonymousMessages(value);
      }

      // Build update object that only changes the specific setting
      const settingsUpdate: any = {};
      settingsUpdate[`settings.${setting}`] = value;

      await setDoc(doc(db, "users", currentUser.uid), settingsUpdate, { merge: true });

      // Refresh user data to reflect changes across the app
      if (refreshUserData) {
        await refreshUserData();
      }

      toast({
        title: "Settings updated",
        description: "Your preferences have been saved",
      });
    } catch (error: any) {
      toast({
        title: "Failed to update settings",
        description: error.message,
        variant: "destructive",
      });

      // Revert on error
      if (setting === "diaryPublic") {
        setDiaryPublic(!value);
      } else if (setting === "allowAnonymousMessages") {
        setAllowAnonymousMessages(!value);
      }
    } finally {
      setSaving(false);
    }
  };

  const handleSignOut = async () => {
    await signOut();
    onClose();
  };

  return (
    <AnimatePresence>
      {open && (
        <>
          {/* Backdrop */}
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="fixed inset-0 bg-black/50 backdrop-blur-sm z-40"
            data-testid="settings-backdrop"
          />

          {/* Panel */}
          <motion.div
            initial={{ x: "100%" }}
            animate={{ x: 0 }}
            exit={{ x: "100%" }}
            transition={{ type: "spring", damping: 25, stiffness: 200 }}
            className="fixed right-0 top-0 bottom-0 w-full sm:w-96 bg-background border-l border-border shadow-2xl z-50 overflow-y-auto"
            data-testid="settings-panel"
          >
            <div className="p-6 space-y-6">
              {/* Header */}
              <div className="flex items-center justify-between">
                <h2 className="text-2xl font-display font-bold">Settings</h2>
                <Button
                  size="icon"
                  variant="ghost"
                  onClick={onClose}
                  data-testid="button-close-settings"
                >
                  <X className="h-5 w-5" />
                </Button>
              </div>

              <Separator />

              {/* Appearance */}
              <div className="space-y-4">
                <h3 className="text-lg font-semibold">Appearance</h3>
                <div className="flex items-center justify-between p-4 rounded-xl border border-border">
                  <div className="flex-1">
                    <Label htmlFor="dark-mode" className="cursor-pointer font-medium">
                      Dark Mode
                    </Label>
                    <p className="text-sm text-muted-foreground">Toggle dark theme</p>
                  </div>
                  <Switch
                    id="dark-mode"
                    checked={darkMode}
                    onCheckedChange={toggleDarkMode}
                    data-testid="switch-dark-mode"
                  />
                </div>
              </div>

              <Separator />

              {/* Privacy */}
              <div className="space-y-4">
                <h3 className="text-lg font-semibold flex items-center gap-2">
                  <Lock className="h-5 w-5" />
                  Privacy
                </h3>

                <div className="flex items-center justify-between p-4 rounded-xl border border-border">
                  <div className="flex-1">
                    <Label htmlFor="diary-public" className="cursor-pointer font-medium">
                      Public Diary
                    </Label>
                    <p className="text-sm text-muted-foreground">
                      Allow others to view your diary entries
                    </p>
                  </div>
                  <Switch
                    id="diary-public"
                    checked={diaryPublic}
                    onCheckedChange={(checked) => handleSettingChange("diaryPublic", checked)}
                    disabled={saving}
                    data-testid="switch-diary-public"
                  />
                </div>

                <div className="flex items-center justify-between p-4 rounded-xl border border-border">
                  <div className="flex-1">
                    <Label htmlFor="anonymous-messages" className="cursor-pointer font-medium">
                      Anonymous Messages
                    </Label>
                    <p className="text-sm text-muted-foreground">
                      Allow users to send you anonymous messages
                    </p>
                  </div>
                  <Switch
                    id="anonymous-messages"
                    checked={allowAnonymousMessages}
                    onCheckedChange={(checked) => handleSettingChange("allowAnonymousMessages", checked)}
                    disabled={saving}
                    data-testid="switch-anonymous-messages"
                  />
                </div>
              </div>

              <Separator />

              {/* Account */}
              <div className="space-y-4">
                <h3 className="text-lg font-semibold flex items-center gap-2">
                  <Users className="h-5 w-5" />
                  Account
                </h3>

                <Card className="p-4">
                  <div className="space-y-2">
                    <p className="text-sm font-medium">Multi-Account Support</p>
                    <p className="text-sm text-muted-foreground">
                      Add and switch between multiple accounts
                    </p>
                    <Button
                      variant="outline"
                      size="sm"
                      className="w-full mt-2"
                      disabled
                      data-testid="button-add-account"
                    >
                      Add Account (Coming Soon)
                    </Button>
                  </div>
                </Card>
              </div>

              <Separator />

              {/* Sign Out */}
              <div className="pt-4">
                <Button
                  onClick={handleSignOut}
                  variant="destructive"
                  className="w-full gap-2"
                  data-testid="button-sign-out"
                >
                  <LogOut className="h-5 w-5" />
                  Sign Out
                </Button>
              </div>

              {/* App Info */}
              <div className="pt-4 text-center text-xs text-muted-foreground">
                <p>Alvice v1.0.0</p>
                <p className="mt-1">Express Yourself, Track Your Mood</p>
              </div>
            </div>
          </motion.div>
        </>
      )}
    </AnimatePresence>
  );
}

